import java.awt.Color; import java.io.*; import java.util.*;
public final class ThemeManager { private ThemeManager(){}
  public record ThemePreset(String name,String base,String surf1,String surf2,String surf3,String textPrimary,String textSecondary,String textDim,String accent,String accentDim,String success,String warning,String error,String border){}
  public static final List<ThemePreset> BUILT_IN=new ArrayList<>(List.of(
    new ThemePreset("Backstage Dark","121212","171717","1E1E1E","252525","E2E2E2","828282","606060","9BF0E1","2A4A45","4ADB7A","DBA64A","DB4A4A","333333"),
    new ThemePreset("Midnight Blue","0D1117","161B22","1C2128","21262D","E6EDF3","8B949E","6E7681","58A6FF","0D2137","3FB950","D29922","F85149","30363D"),
    new ThemePreset("Solarized Dark","002B36","073642","003847","004052","839496","657B83","586E75","2AA198","002D38","859900","CB4B16","DC322F","073642"),
    new ThemePreset("Amber Terminal","0D0D00","1A1A00","1F1F00","252500","FFB000","CC8800","996600","FFB000","2A2200","88BB00","FF6600","FF2200","333300"),
    new ThemePreset("Forest Green","0A1A0A","0F230F","122312","152515","C8E6C9","81C784","4CAF50","4CAF50","0A2A0A","8BC34A","FFC107","EF5350","1B5E20"),
    new ThemePreset("High Contrast","000000","0A0A0A","111111","1A1A1A","FFFFFF","CCCCCC","888888","FFFFFF","1A1A1A","00FF00","FFFF00","FF0000","444444")));
  public static void apply(ThemePreset p){Theme.BASE=h(p.base());Theme.SURFACE_1=h(p.surf1());Theme.SURFACE_2=h(p.surf2());Theme.SURFACE_3=h(p.surf3());Theme.TEXT_PRIMARY=h(p.textPrimary());Theme.TEXT_SECONDARY=h(p.textSecondary());Theme.TEXT_DIM=h(p.textDim());Theme.ACCENT=h(p.accent());Theme.ACCENT_DIM=h(p.accentDim());Theme.SUCCESS=h(p.success());Theme.WARNING=h(p.warning());Theme.ERROR=h(p.error());Theme.BORDER=h(p.border());}
  public static void exportToFile(ThemePreset p,File f)throws IOException{Properties pr=new Properties();pr.setProperty("name",p.name());pr.setProperty("base",p.base());pr.setProperty("surf1",p.surf1());pr.setProperty("surf2",p.surf2());pr.setProperty("surf3",p.surf3());pr.setProperty("textPrimary",p.textPrimary());pr.setProperty("textSecondary",p.textSecondary());pr.setProperty("textDim",p.textDim());pr.setProperty("accent",p.accent());pr.setProperty("accentDim",p.accentDim());pr.setProperty("success",p.success());pr.setProperty("warning",p.warning());pr.setProperty("error",p.error());pr.setProperty("border",p.border());try(FileWriter fw=new FileWriter(f)){pr.store(fw,"j8085 Theme");}}
  public static ThemePreset importFromFile(File f)throws IOException{Properties p=new Properties();try(FileReader fr=new FileReader(f)){p.load(fr);}return new ThemePreset(p.getProperty("name","Custom"),p.getProperty("base","121212"),p.getProperty("surf1","171717"),p.getProperty("surf2","1E1E1E"),p.getProperty("surf3","252525"),p.getProperty("textPrimary","E2E2E2"),p.getProperty("textSecondary","828282"),p.getProperty("textDim","606060"),p.getProperty("accent","9BF0E1"),p.getProperty("accentDim","2A4A45"),p.getProperty("success","4ADB7A"),p.getProperty("warning","DBA64A"),p.getProperty("error","DB4A4A"),p.getProperty("border","333333"));}
  private static Color h(String hex){try{return new Color(Integer.parseInt(hex.replace("#",""),16));}catch(NumberFormatException e){return Color.GRAY;}}
}
